import type { MessageNormalizer } from '../../normalization/pipeline';
import { parseNumeric, splitConcatenatedSymbol } from '../../normalization/pipeline';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedTick, NormalizedTrade } from '../../types/normalized';
import type {
  BybitKlineData,
  BybitOrderbookData,
  BybitRawKline,
  BybitRawMessage,
  BybitRawTrade,
  BybitRestKline,
  BybitTickerData,
  BybitTradeData,
} from './bybit-types';

/**
 * Normalizes raw Bybit V5 WebSocket and REST messages.
 *
 * Handles:
 * - Topic-based message routing (kline.*, trade.*, orderbook.*, tickers.*)
 * - Delta vs snapshot order book types
 * - Numeric strings -> JavaScript numbers
 * - BTCUSDT -> BTC/USDT symbol normalization
 * - Bybit interval naming (1, 3, 60, D, W, M)
 */
export class BybitNormalizer implements MessageNormalizer<BybitRawMessage> {
  parseMessage(raw: string): BybitRawMessage | undefined {
    try {
      const parsed: unknown = JSON.parse(raw);
      if (typeof parsed !== 'object' || parsed === null) return undefined;

      // Skip pong and subscription responses
      if ('op' in parsed || 'ret_msg' in parsed || 'success' in parsed) return undefined;

      // Must have topic and data fields
      if (!('topic' in parsed && 'data' in parsed)) return undefined;

      return parsed as BybitRawMessage;
    } catch {
      return undefined;
    }
  }

  normalizeTicker(raw: BybitRawMessage): NormalizedTick | undefined {
    if (!raw.topic.startsWith('tickers.')) return undefined;
    const data = raw.data as BybitTickerData;

    const lastPrice = parseNumeric(data.lastPrice);
    const prevPrice = parseNumeric(data.prevPrice24h);
    const priceChange = lastPrice - prevPrice;
    const symbol = splitConcatenatedSymbol(data.symbol);

    return {
      symbol,
      lastPrice,
      priceChange,
      priceChangePercent: parseNumeric(data.price24hPcnt) * 100,
      high24h: parseNumeric(data.highPrice24h),
      low24h: parseNumeric(data.lowPrice24h),
      volume24h: parseNumeric(data.volume24h),
      quoteVolume24h: parseNumeric(data.turnover24h),
      timestamp: raw.ts,
      bestBid: parseNumeric(data.bid1Price),
      bestBidQty: parseNumeric(data.bid1Size),
      bestAsk: parseNumeric(data.ask1Price),
      bestAskQty: parseNumeric(data.ask1Size),
    };
  }

  normalizeTrade(raw: BybitRawMessage): NormalizedTrade | undefined {
    if (!raw.topic.startsWith('publicTrade.')) return undefined;
    const trades = raw.data as unknown as BybitTradeData;
    const trade: BybitRawTrade | undefined = trades[0];
    if (!trade) return undefined;

    const side = trade.S === 'Buy' ? 'buy' as const : 'sell' as const;
    return {
      id: trade.i,
      timestamp: trade.T,
      price: parseNumeric(trade.p),
      quantity: parseNumeric(trade.v),
      side,
      buyerMaker: side === 'sell',
    };
  }

  normalizeOHLCV(raw: BybitRawMessage): NormalizedOHLCV | undefined {
    if (!raw.topic.startsWith('kline.')) return undefined;
    const klines = raw.data as unknown as BybitKlineData;
    const kline: BybitRawKline | undefined = klines[0];
    if (!kline) return undefined;

    return {
      timestamp: kline.start,
      open: parseNumeric(kline.open),
      high: parseNumeric(kline.high),
      low: parseNumeric(kline.low),
      close: parseNumeric(kline.close),
      volume: parseNumeric(kline.volume),
      quoteVolume: parseNumeric(kline.turnover),
      tradeCount: 0,
      closed: kline.confirm,
    };
  }

  normalizeOrderbook(raw: BybitRawMessage): NormalizedOrderbook | undefined {
    if (!raw.topic.startsWith('orderbook.')) return undefined;
    const data = raw.data as BybitOrderbookData;
    const symbol = splitConcatenatedSymbol(data.s);

    return {
      symbol,
      timestamp: raw.ts,
      bids: data.b.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      asks: data.a.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      sequenceId: data.seq,
      type: raw.type,
    };
  }

  /** Normalize a REST kline (positional string array) into NormalizedOHLCV. */
  normalizeRestKline(kline: BybitRestKline): NormalizedOHLCV {
    return {
      timestamp: parseNumeric(kline[0]),
      open: parseNumeric(kline[1]),
      high: parseNumeric(kline[2]),
      low: parseNumeric(kline[3]),
      close: parseNumeric(kline[4]),
      volume: parseNumeric(kline[5]),
      quoteVolume: parseNumeric(kline[6]),
      tradeCount: 0,
      closed: true,
    };
  }
}
