import type {
  AdapterCapabilities,
  AdapterCategory,
  AdapterSubscription,
  ConnectionStatus,
  ExchangeAdapter,
  ExchangeConfig,
  HealthMetrics,
  OHLCVCallback,
  OrderbookCallback,
  StatusCallback,
  TickerCallback,
  TradeCallback,
} from '../../types/adapter';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedSymbol, NormalizedTrade, Timeframe } from '../../types/normalized';
import { createSubscriptionId, splitConcatenatedSymbol, parseNumeric } from '../../normalization/pipeline';
import { RateLimiter, EXCHANGE_RATE_LIMITS } from '../../rate-limiter/rate-limiter';
import { BybitNormalizer } from './bybit-normalizer';
import type { BybitCategory, BybitInstrumentInfo, BybitRawMessage, BybitRestKline } from './bybit-types';

const WS_ENDPOINTS: Readonly<Record<BybitCategory, string>> = {
  spot: 'wss://stream.bybit.com/v5/public/spot',
  linear: 'wss://stream.bybit.com/v5/public/linear',
  inverse: 'wss://stream.bybit.com/v5/public/inverse',
};

const TESTNET_WS_ENDPOINTS: Readonly<Record<BybitCategory, string>> = {
  spot: 'wss://stream-testnet.bybit.com/v5/public/spot',
  linear: 'wss://stream-testnet.bybit.com/v5/public/linear',
  inverse: 'wss://stream-testnet.bybit.com/v5/public/inverse',
};

import { CircuitBreaker } from '../../circuit-breaker/circuit-breaker';

const DEFAULT_REST_URL = 'https://api.bybit.com';
const TESTNET_REST_URL = 'https://api-testnet.bybit.com';

/** Client-side ping interval (20 seconds). */
const PING_INTERVAL_MS = 20_000;

/** Default heartbeat timeout for Bybit (60 seconds). */
const DEFAULT_HEARTBEAT_TIMEOUT_MS = 60_000;

/** Timeframe to Bybit interval mapping. */
const INTERVAL_MAP: Readonly<Record<Timeframe, string>> = {
  '1s': '1', '5s': '1', '15s': '1', '30s': '1',
  '1m': '1', '3m': '3', '5m': '5', '15m': '15', '30m': '30',
  '1h': '60', '2h': '120', '4h': '240', '6h': '360', '8h': '480', '12h': '720',
  '1d': 'D', '3d': 'D', '1w': 'W', '1M': 'M',
};

interface ActiveSubscription {
  readonly id: string;
  readonly symbol: string;
  readonly topic: string;
  readonly type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv' | 'status';
  readonly callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback | StatusCallback;
  readonly category: BybitCategory;
}

/**
 * Bybit V5 exchange adapter.
 *
 * Features:
 * - Separate WebSocket connections per product category (spot/linear/inverse)
 * - Client-side ping every 20 seconds
 * - Delta order book reconstruction
 * - Rate-limited REST API calls
 */
export class BybitAdapter implements ExchangeAdapter {
  readonly exchangeId = 'bybit' as const;
  readonly displayName = 'Bybit';
  readonly category: AdapterCategory = 'cex';
  readonly capabilities: AdapterCapabilities = {
    realtime: true,
    historicalDepth: '7y',
    orderbook: true,
    trades: true,
    ohlcv: true,
    fundingRates: true,
    openInterest: false,
    liquidations: false,
    defiMetrics: false,
    onChainMetrics: false,
    authenticated: true,
  };

  private readonly connections = new Map<BybitCategory, WebSocket>();
  private readonly pingTimers = new Map<BybitCategory, ReturnType<typeof setInterval>>();
  private config: ExchangeConfig | null = null;
  private readonly normalizer = new BybitNormalizer();
  private rateLimiter: RateLimiter | null = null;
  private readonly subscriptions = new Map<string, ActiveSubscription>();
  private readonly statusCallbacks = new Map<string, StatusCallback>();
  private connectionState: ConnectionStatus = {
    state: 'disconnected',
    latencyMs: 0,
    messagesPerSecond: 0,
    lastMessageAt: 0,
    reconnectAttempt: 0,
    uptime: 0,
  };
  private connectTime = 0;
  private reconnectAttempt = 0;
  private reconnectTimer: ReturnType<typeof setTimeout> | undefined;
  private messageCount = 0;
  private messageRateWindowStart = 0;
  private readonly circuitBreaker = new CircuitBreaker();
  private heartbeatTimer: ReturnType<typeof setTimeout> | undefined;
  private heartbeatTimeoutMs = DEFAULT_HEARTBEAT_TIMEOUT_MS;
  private totalErrors = 0;
  private totalRequests = 0;

  async connect(config: ExchangeConfig): Promise<void> {
    this.config = config;
    this.heartbeatTimeoutMs = config.heartbeatTimeoutMs ?? DEFAULT_HEARTBEAT_TIMEOUT_MS;
    if (config.circuitBreaker) {
      this.circuitBreaker.reset();
    }
    const rateLimitConfig = EXCHANGE_RATE_LIMITS['bybit'];
    if (rateLimitConfig) {
      this.rateLimiter = new RateLimiter('bybit', rateLimitConfig);
    }
    await this.circuitBreaker.execute(() => this.connectCategory('spot'));
  }

  async disconnect(): Promise<void> {
    this.clearTimers();
    this.stopHeartbeat();
    for (const [category, ws] of this.connections) {
      ws.onclose = null;
      ws.onerror = null;
      ws.onmessage = null;
      ws.close();
      const pingTimer = this.pingTimers.get(category);
      if (pingTimer !== undefined) {
        clearInterval(pingTimer);
      }
    }
    this.connections.clear();
    this.pingTimers.clear();
    this.subscriptions.clear();
    this.statusCallbacks.clear();
    this.rateLimiter?.dispose();
    this.rateLimiter = null;
    this.circuitBreaker.reset();
    this.updateState('disconnected');
  }

  getStatus(): ConnectionStatus {
    return { ...this.connectionState, uptime: this.getUptime() };
  }

  getHealthMetrics(): HealthMetrics {
    const status = this.getStatus();
    const uptimeSeconds = status.uptime;
    const uptimePercent = uptimeSeconds > 0
      ? Math.min(100, (uptimeSeconds / (uptimeSeconds + this.reconnectAttempt * 5)) * 100)
      : 0;
    return {
      connected: status.state === 'connected',
      latencyMs: status.latencyMs,
      messagesPerSecond: status.messagesPerSecond,
      uptimePercent,
      lastMessageAt: status.lastMessageAt,
      errorRate: this.totalRequests > 0 ? this.totalErrors / this.totalRequests : 0,
      circuitBreakerState: this.circuitBreaker.state,
    };
  }

  onStatusChange(callback: StatusCallback): AdapterSubscription {
    const id = createSubscriptionId('bybit', 'status', '_global');
    this.statusCallbacks.set(id, callback);
    return {
      id,
      symbol: '_global',
      type: 'status',
      dispose: () => { this.statusCallbacks.delete(id); },
    };
  }

  subscribeTicker(symbol: string, callback: TickerCallback): AdapterSubscription {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const topic = `tickers.${exchangeSymbol}`;
    return this.addSubscription(symbol, topic, 'ticker', callback, 'spot');
  }

  subscribeOrderbook(symbol: string, depth: number, callback: OrderbookCallback): AdapterSubscription {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const depthLevel = depth <= 1 ? 1 : depth <= 25 ? 25 : depth <= 50 ? 50 : 200;
    const topic = `orderbook.${depthLevel}.${exchangeSymbol}`;
    return this.addSubscription(symbol, topic, 'orderbook', callback, 'spot');
  }

  subscribeTrades(symbol: string, callback: TradeCallback): AdapterSubscription {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const topic = `publicTrade.${exchangeSymbol}`;
    return this.addSubscription(symbol, topic, 'trades', callback, 'spot');
  }

  subscribeOHLCV(symbol: string, timeframe: Timeframe, callback: OHLCVCallback): AdapterSubscription {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const interval = INTERVAL_MAP[timeframe];
    const topic = `kline.${interval}.${exchangeSymbol}`;
    return this.addSubscription(symbol, topic, 'ohlcv', callback, 'spot');
  }

  async getCandles(symbol: string, timeframe: Timeframe, from: number, to: number): Promise<NormalizedOHLCV[]> {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const interval = INTERVAL_MAP[timeframe];
    const url = `${this.getRestUrl()}/v5/market/kline?category=spot&symbol=${exchangeSymbol}&interval=${interval}&start=${from}&end=${to}&limit=1000`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Bybit REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as { result: { list: BybitRestKline[] } };
    return data.result.list.map(kline => this.normalizer.normalizeRestKline(kline));
  }

  async getOrderbookSnapshot(symbol: string, depth: number): Promise<NormalizedOrderbook> {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const limit = Math.min(depth, 200);
    const url = `${this.getRestUrl()}/v5/market/orderbook?category=spot&symbol=${exchangeSymbol}&limit=${limit}`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Bybit REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as {
      result: {
        s: string;
        b: [string, string][];
        a: [string, string][];
        u: number;
        seq: number;
        ts: number;
      };
    };

    const normalizedSymbol = splitConcatenatedSymbol(data.result.s);
    return {
      symbol: normalizedSymbol,
      timestamp: data.result.ts,
      bids: data.result.b.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      asks: data.result.a.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      sequenceId: data.result.seq,
      type: 'snapshot',
    };
  }

  async getRecentTrades(symbol: string, limit: number): Promise<NormalizedTrade[]> {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const url = `${this.getRestUrl()}/v5/market/recent-trade?category=spot&symbol=${exchangeSymbol}&limit=${Math.min(limit, 1000)}`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Bybit REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as {
      result: {
        list: Array<{
          execId: string;
          symbol: string;
          price: string;
          size: string;
          side: 'Buy' | 'Sell';
          time: string;
          isBlockTrade: boolean;
        }>;
      };
    };

    return data.result.list.map(t => ({
      id: t.execId,
      timestamp: parseNumeric(t.time),
      price: parseNumeric(t.price),
      quantity: parseNumeric(t.size),
      side: t.side === 'Buy' ? 'buy' as const : 'sell' as const,
      buyerMaker: t.side === 'Sell',
    }));
  }

  async getSymbols(): Promise<NormalizedSymbol[]> {
    const url = `${this.getRestUrl()}/v5/market/instruments-info?category=spot`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Bybit REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as { result: { list: BybitInstrumentInfo[] } };

    return data.result.list
      .filter(s => s.status === 'Trading')
      .map(s => this.normalizeInstrumentInfo(s));
  }

  private normalizeInstrumentInfo(raw: BybitInstrumentInfo): NormalizedSymbol {
    return {
      symbol: `${raw.baseCoin}/${raw.quoteCoin}`,
      base: raw.baseCoin,
      quote: raw.quoteCoin,
      exchangeSymbol: raw.symbol,
      exchangeId: 'bybit',
      type: 'spot',
      pricePrecision: this.countDecimals(raw.priceFilter.tickSize),
      quantityPrecision: this.countDecimals(raw.lotSizeFilter.basePrecision),
      minQuantity: parseNumeric(raw.lotSizeFilter.minOrderQty),
      tickSize: parseNumeric(raw.priceFilter.tickSize),
      active: raw.status === 'Trading',
    };
  }

  private countDecimals(value: string): number {
    const parts = value.split('.');
    return parts[1]?.replace(/0+$/, '').length ?? 0;
  }

  private addSubscription(
    symbol: string,
    topic: string,
    type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv',
    callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback,
    category: BybitCategory,
  ): AdapterSubscription {
    const id = createSubscriptionId('bybit', type, symbol);
    const sub: ActiveSubscription = { id, symbol, topic, type, callback, category };
    this.subscriptions.set(id, sub);

    this.ensureCategoryConnection(category).then(() => {
      const ws = this.connections.get(category);
      if (ws?.readyState === WebSocket.OPEN) {
        this.sendSubscribe(ws, [topic]);
      }
    }).catch(() => {
      // Connection will be retried via reconnect logic
    });

    return {
      id,
      symbol,
      type,
      dispose: () => {
        this.subscriptions.delete(id);
        const stillUsed = Array.from(this.subscriptions.values()).some(s => s.topic === topic);
        if (!stillUsed) {
          const ws = this.connections.get(category);
          if (ws?.readyState === WebSocket.OPEN) {
            this.sendUnsubscribe(ws, [topic]);
          }
        }
      },
    };
  }

  private async ensureCategoryConnection(category: BybitCategory): Promise<void> {
    if (this.connections.has(category)) return;
    await this.connectCategory(category);
  }

  private async connectCategory(category: BybitCategory): Promise<void> {
    this.updateState('connecting');
    const wsUrl = this.getWsUrl(category);

    return new Promise<void>((resolve, reject) => {
      let ws: WebSocket;
      try {
        ws = new WebSocket(wsUrl);
      } catch (err) {
        this.updateState('error', err instanceof Error ? err.message : 'WebSocket creation failed');
        reject(err);
        return;
      }

      ws.onopen = () => {
        this.connections.set(category, ws);
        this.connectTime = Date.now();
        this.reconnectAttempt = 0;
        this.messageRateWindowStart = Date.now();
        this.messageCount = 0;
        this.updateState('connected');
        this.startHeartbeat();

        // Start client-side ping
        const pingTimer = setInterval(() => {
          if (ws.readyState === WebSocket.OPEN) {
            ws.send(JSON.stringify({ op: 'ping' }));
          }
        }, PING_INTERVAL_MS);
        this.pingTimers.set(category, pingTimer);

        // Resubscribe to active topics for this category
        const topics = this.getTopicsForCategory(category);
        if (topics.length > 0) {
          this.sendSubscribe(ws, topics);
        }

        resolve();
      };

      ws.onmessage = (event: MessageEvent) => {
        this.handleMessage(event.data as string);
      };

      ws.onerror = () => {
        this.updateState('error', `WebSocket error on ${category}`);
      };

      ws.onclose = () => {
        this.connections.delete(category);
        const timer = this.pingTimers.get(category);
        if (timer !== undefined) {
          clearInterval(timer);
          this.pingTimers.delete(category);
        }
        if (this.connectionState.state !== 'disconnected') {
          this.reconnectCategory(category);
        }
      };
    });
  }

  private handleMessage(rawData: string): void {
    this.messageCount++;
    this.resetHeartbeat();
    const now = Date.now();
    const elapsed = now - this.messageRateWindowStart;
    if (elapsed >= 10_000) {
      this.connectionState = {
        ...this.connectionState,
        messagesPerSecond: this.messageCount / (elapsed / 1000),
        lastMessageAt: now,
      };
      this.messageCount = 0;
      this.messageRateWindowStart = now;
    }

    const message = this.normalizer.parseMessage(rawData);
    if (!message) return;

    for (const sub of this.subscriptions.values()) {
      switch (sub.type) {
        case 'ticker': {
          const tick = this.normalizer.normalizeTicker(message);
          if (tick) (sub.callback as TickerCallback)(tick);
          break;
        }
        case 'trades': {
          const trade = this.normalizer.normalizeTrade(message);
          if (trade) (sub.callback as TradeCallback)(trade);
          break;
        }
        case 'ohlcv': {
          const candle = this.normalizer.normalizeOHLCV(message);
          if (candle) (sub.callback as OHLCVCallback)(candle);
          break;
        }
        case 'orderbook': {
          const book = this.normalizer.normalizeOrderbook(message);
          if (book) (sub.callback as OrderbookCallback)(book);
          break;
        }
      }
    }
  }

  private reconnectCategory(category: BybitCategory): void {
    if (this.connectionState.state === 'disconnected') return;
    this.stopHeartbeat();
    this.circuitBreaker.recordFailure();
    this.reconnectAttempt++;
    this.totalErrors++;
    this.updateState('reconnecting');

    const baseDelay = Math.min(1000 * Math.pow(2, this.reconnectAttempt - 1), 16_000);
    const jitter = Math.random() * baseDelay * 0.25;
    const delay = this.reconnectAttempt === 1 ? 0 : baseDelay + jitter;

    this.reconnectTimer = setTimeout(() => {
      this.circuitBreaker.execute(() => this.connectCategory(category)).catch(() => {
        this.reconnectCategory(category);
      });
    }, delay);
  }

  private getTopicsForCategory(category: BybitCategory): string[] {
    const topics = new Set<string>();
    for (const sub of this.subscriptions.values()) {
      if (sub.category === category) {
        topics.add(sub.topic);
      }
    }
    return Array.from(topics);
  }

  private sendSubscribe(ws: WebSocket, topics: string[]): void {
    if (ws.readyState !== WebSocket.OPEN || topics.length === 0) return;
    ws.send(JSON.stringify({ op: 'subscribe', args: topics }));
  }

  private sendUnsubscribe(ws: WebSocket, topics: string[]): void {
    if (ws.readyState !== WebSocket.OPEN || topics.length === 0) return;
    ws.send(JSON.stringify({ op: 'unsubscribe', args: topics }));
  }

  private updateState(state: ConnectionStatus['state'], errorMessage?: string): void {
    this.connectionState = {
      state,
      latencyMs: this.connectionState.latencyMs,
      messagesPerSecond: this.connectionState.messagesPerSecond,
      lastMessageAt: this.connectionState.lastMessageAt,
      errorMessage,
      reconnectAttempt: this.reconnectAttempt,
      uptime: this.getUptime(),
    };
    for (const callback of this.statusCallbacks.values()) {
      callback(this.connectionState);
    }
  }

  private getUptime(): number {
    if (this.connectTime === 0) return 0;
    return (Date.now() - this.connectTime) / 1000;
  }

  private getWsUrl(category: BybitCategory): string {
    if (this.config?.wsUrl) return this.config.wsUrl;
    const endpoints = this.config?.testnet ? TESTNET_WS_ENDPOINTS : WS_ENDPOINTS;
    return endpoints[category];
  }

  private getRestUrl(): string {
    if (this.config?.restUrl) return this.config.restUrl;
    return this.config?.testnet ? TESTNET_REST_URL : DEFAULT_REST_URL;
  }

  private toExchangeSymbol(symbol: string): string {
    return symbol.replace('/', '');
  }

  private startHeartbeat(): void {
    this.stopHeartbeat();
    this.heartbeatTimer = setTimeout(() => {
      this.onHeartbeatTimeout();
    }, this.heartbeatTimeoutMs);
  }

  private resetHeartbeat(): void {
    if (this.heartbeatTimer !== undefined) {
      clearTimeout(this.heartbeatTimer);
      this.heartbeatTimer = setTimeout(() => {
        this.onHeartbeatTimeout();
      }, this.heartbeatTimeoutMs);
    }
  }

  private stopHeartbeat(): void {
    if (this.heartbeatTimer !== undefined) {
      clearTimeout(this.heartbeatTimer);
      this.heartbeatTimer = undefined;
    }
  }

  private onHeartbeatTimeout(): void {
    this.updateState('error', 'Heartbeat timeout');
    // Reconnect all active categories
    for (const category of this.connections.keys()) {
      this.reconnectCategory(category);
    }
  }

  private clearTimers(): void {
    if (this.reconnectTimer !== undefined) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = undefined;
    }
  }
}
